import { useEffect, useState } from "react";
import axios from "axios";

export default function CustomerDashboard() {

  const user =
    JSON.parse(localStorage.getItem("user"));

  const [workers, setWorkers] =
    useState([]);

  const [requests, setRequests] =
    useState([]);

  const [skill, setSkill] =
    useState("");

  const [location, setLocation] =
    useState("");

  const [date, setDate] =
    useState("");

  const [selectedWorker, setSelectedWorker] =
    useState("");

  const [rating, setRating] =
    useState("");

  const [review, setReview] =
    useState("");

  // fetch workers
  useEffect(() => {
    fetchWorkers();
    fetchRequests();
  }, []);

  const fetchWorkers = async () => {
    const res = await axios.get(
      "http://localhost:5000/api/auth/workers"
    );
    setWorkers(res.data);
  };

  const fetchRequests = async () => {
    const res = await axios.get(
      `http://localhost:5000/api/request/customer/${user.name}`
    );
    setRequests(res.data);
  };

  // send request
  const sendRequest = async () => {

    const worker =
      workers.find(
        (w) => w._id === selectedWorker
      );

    await axios.post(
      "http://localhost:5000/api/request/send",
      {
        customerName: user.name,
        customerId: user._id,

        labourId: worker._id,
        labourName: worker.name,

        workType: skill,
        location,
        date,
        timings: []
      }
    );

    alert("Request Sent");
    fetchRequests();
  };

  // customer final accept
  const acceptLabour = async (id) => {

    await axios.put(
      `http://localhost:5000/api/request/customer-decision/${id}`,
      {
        decision: "Accepted"
      }
    );

    fetchRequests();
  };

  // customer reject
  const rejectLabour = async (id) => {

    await axios.put(
      `http://localhost:5000/api/request/customer-decision/${id}`,
      {
        decision: "Rejected"
      }
    );

    fetchRequests();
  };

  // feedback
  const submitFeedback = async (id) => {

    await axios.put(
      `http://localhost:5000/api/request/feedback/${id}`,
      {
        rating,
        comment: review
      }
    );

    alert("Feedback Submitted");
    fetchRequests();
  };

  const filteredWorkers =
    workers.filter((w) =>
      w.skills?.includes(skill)
    );

  return (

    <div style={styles.page}>

      <h2>Customer Dashboard</h2>

      {/* SEARCH */}
      <div style={styles.card}>

        <select
          style={styles.input}
          onChange={(e) =>
            setSkill(e.target.value)
          }
        >
          <option>Select Worker Type</option>
          <option>Electrician</option>
          <option>Plumber</option>
          <option>Painter</option>
          <option>Carpenter</option>
        </select>

        <input
          style={styles.input}
          placeholder="Location"
          onChange={(e) =>
            setLocation(e.target.value)
          }
        />

        <input
          type="date"
          style={styles.input}
          onChange={(e) =>
            setDate(e.target.value)
          }
        />

        <select
          style={styles.input}
          onChange={(e) =>
            setSelectedWorker(
              e.target.value
            )
          }
        >
          <option>Select Worker</option>

          {filteredWorkers.map((w) => (
            <option
              key={w._id}
              value={w._id}
            >
              {w.name}
            </option>
          ))}

        </select>

        <button
          style={styles.button}
          onClick={sendRequest}
        >
          Send Request
        </button>

      </div>

      {/* REQUEST STATUS */}
      <h3>My Requests</h3>

      {requests.map((req) => (

        <div
          key={req._id}
          style={styles.card}
        >

          <p>
            Worker:
            {req.labourName}
          </p>

          <p>
            Status:
            {req.status}
          </p>

          <p>
            Labour Price:
            ₹{req.labourPrice}
          </p>

          <p>
            Customer Decision:
            {req.customerDecision}
          </p>

          {/* if labour accepted */}
          {req.status ===
            "accepted" &&
            req.customerDecision ===
              "Waiting" && (

            <>
              <button
                style={styles.button}
                onClick={() =>
                  acceptLabour(
                    req._id
                  )
                }
              >
                Accept
              </button>

              <button
                style={styles.reject}
                onClick={() =>
                  rejectLabour(
                    req._id
                  )
                }
              >
                Reject
              </button>
            </>
          )}

          {/* feedback */}
          {req.customerDecision ===
            "Accepted" && (

            <>
              <input
                placeholder="Rating 1-5"
                style={
                  styles.input
                }
                onChange={(e)=>
                  setRating(
                    e.target.value
                  )
                }
              />

              <textarea
                placeholder="Review"
                style={
                  styles.input
                }
                onChange={(e)=>
                  setReview(
                    e.target.value
                  )
                }
              />

              <button
                style={
                  styles.button
                }
                onClick={() =>
                  submitFeedback(
                    req._id
                  )
                }
              >
                Submit Review
              </button>
            </>
          )}

        </div>
      ))}
    </div>
  );
}

const styles = {
  page:{
    padding:"30px",
    background:"#f4f7fb",
    minHeight:"100vh"
  },

  card:{
    background:"white",
    padding:"20px",
    marginBottom:"20px",
    borderRadius:"12px"
  },

  input:{
    width:"100%",
    padding:"12px",
    marginBottom:"10px"
  },

  button:{
    background:"#2563eb",
    color:"white",
    border:"none",
    padding:"10px 20px"
  },

  reject:{
    background:"red",
    color:"white",
    border:"none",
    padding:"10px 20px",
    marginLeft:"10px"
  }
};
